mapper.select:
SELECT

    ${col} 

FROM gc_student s
LEFT JOIN gc_college c ON s.college_id = c.id
LEFT JOIN gc_major m ON s.major_id = m.id
LEFT JOIN gc_class cl ON s.class_id = cl.id
LEFT JOIN gc_subsidy_apply sa ON s.id = sa.student_id
WHERE s.is_deleted = 0

    AND s.college_id = #{filters.collegeId}


    AND sa.status = #{filters.status}
